userErrorTypename.query:
mutation BackupRegionUpdateValidationTypename {
  backupRegionUpdate(region: { countryCode: ZZ }) {
    backupRegion {
      id
    }
    userErrors {
      __typename
      field
      message
      code
    }
  }
}

